type characterRange struct {
	low  rune
	high rune
}

func setContains(ranges []characterRange, c rune) bool {
	lo, hi := 0, len(ranges)
	for lo < hi {
		mid := lo + (hi-lo)/2
		if c < ranges[mid].low {
			hi = mid
		} else if c > ranges[mid].high {
			lo = mid + 1
		} else {
			return true
		}
	}
	return false
}

